import{_ as t,o as a,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"3I. Veteran Employment Support Officer","description":"","frontmatter":{"title":"3I. Veteran Employment Support Officer","eba":"Health Allied & Managers Admin 2021-2025","topics":["schedules","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/schedules/3i-veteran-employment-support-officer.md","filePath":"ebas/has-managers-admin/schedules/3i-veteran-employment-support-officer.md"}'),i={name:"ebas/has-managers-admin/schedules/3i-veteran-employment-support-officer.md"};function o(s,e,p,l,c,m){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_3i-veteran-employment-support-officer" tabindex="-1">3I. Veteran Employment Support Officer <a class="header-anchor" href="#_3i-veteran-employment-support-officer" aria-label="Permalink to &quot;3I. Veteran Employment Support Officer&quot;">​</a></h1><p>Formatting note</p><p>The schedule body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find schedules by their title, number, topic or synonyms.</p><p>```text OFFICER 1. The Role 1.1 A Veteran Employment Support Officer will be responsible for promoting the achievement of the Veteran workforce target and the prioritisation of focus areas set out in the Public Sector Veteran Employment Strategy:</p><ol><li><p>Duties Duties include:</p><p>2.1 Development and/or maintenance of the local Veteran Employment Plan which aims to increase the Veteran workforce across all areas of the organisation.</p><p>2.2 Promote the focus areas set out in the Public Sector Veteran Employment Strategy to help Veterans translate their military experience into relevant experience for the public sector.</p><p>2.3 Networking with the Australian Defence Force (ADF) Veteran community, Veteran service provider organisations, TAFE and University.</p></li><li><p>Qualifications/Experience Required qualifications and experience for this role is as follows:</p><p>3.1 Is a veteran or can establish evidence of a long-standing commitment to supporting and promoting the individual needs, skills, abilities and personal goals of Veterans.</p><p>3.2 Relevant tertiary qualifications in Human Resources (or equivalent) or significant experience in Veteran Employment, Recruitment and Engagement.</p></li></ol><p>SIGNATURES</p><p>SIGNATURES</p><p>[2022] FWCA 1295</p><p>DECISION Fair Work Act 2009 s.185—Enterprise agreement</p><p>Victorian Hospitals’ Industrial Association (AG2022/764)</p><p>HEALTH AND ALLIED SERVICES, MANAGERS AND ADMINISTRATIVE WORKERS (VICTORIAN PUBLIC SECTOR) (SINGLE INTEREST EMPLOYERS) ENTERPRISE AGREEMENT 2021- Health and welfare services</p><p>DEPUTY PRESIDENT MASSON MELBOURNE, 13 APRIL 2022 Application for approval of the Health and Allied Services, Managers and Administrative Workers (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2021- 2025. [1] An application has been made for approval of an enterprise agreement known as the Health and Allied Services, Managers and Administrative Workers (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2021-2025 (the Agreement). The application was made pursuant to s.185 of the Fair Work Act 2009 (the Act). It has been made by Victorian Hospitals’ Industrial Association. The Agreement is a single enterprise agreement. [2] The Employer has provided written undertakings. A copy of the undertakings is attached in Annexure A. I am satisfied that the undertakings will not cause financial detriment to any employee covered by the Agreement and that the undertakings will not result in substantial changes to the Agreement. The undertakings are taken to be a term of the Agreement. [3] Subject to the undertakings referred to above, I am satisfied that each of the requirements of ss.186, 187, 188 and 190 as are relevant to this application for approval have been met. [4] I note that several clauses of the Agreement may be inconsistent with the National Employment Standards. Given the National Employment Standards precedence clause at clause 8.2 of the Agreement, I am satisfied that the more beneficial entitlements of the NES will prevail.</p><p>[2022] FWCA 1295 [5] The Health Services Union, being a bargaining representative for the Agreement, has given notice under s.183 of the Act that it wants the Agreement to cover it. In accordance with s.201(2) I note that the Agreement covers the organisation. [6] The Agreement is approved and, in accordance with s.54 of the Act, will operate from 20 April 2022. The nominal expiry date of the Agreement is 30 June 2025.</p><pre><code> DEPUTY PRESIDENT\n\n Printed by authority of the Commonwealth Government Printer\n &lt;AE515689 PR740335&gt;\n</code></pre><p>```</p>',15)])])}const f=t(i,[["render",o]]);export{d as __pageData,f as default};
